RuleSet.GenFile:
// Description: C++18 Command Line Object Implementation for $SchemaName$ RAM Loader

$MssSourceLicense$

#include <cflib/ICFLibPublic.hpp>
#include <$lower SchemaName$/I$SchemaName$Public.hpp>
#include <$lower SchemaName$obj/I$SchemaName$ObjPublic.hpp>
#include <$lower SchemaName$obj/$SchemaName$SchemaObj.hpp>
#include <$poptop SchemaDef lower SchemaName$saxloader/$poptop SchemaDef SchemaName$SaxLoaderPublic.hpp>
#include <$lower SchemaName$ram/$SchemaName$RamSchema.hpp>
#include <$SchemaName$RamLdr.hpp>

using namespace std;

namespace $CPlusNamespace$ {

	cflib::ICFLibMessageLog* $SchemaName$RamLdr::log = new cflib::CFLibConsoleMessageLog();
$implSchemaRamLdrConstructor$
$implSchemaRamLdrEvalRemaining$
}

RuleSet.GenRule:
void $SchemaName$RamLdr::evaluateRemainingArgs( size_t argc, char* argv[], size_t consumed ) {
	// There are no extra arguments for the RAM "database" instance
	if( argc > consumed ) {
		if( log != NULL ) {
			log->message( "$SchemaName$RamLdr.evaluateRemainingArgs() WARNING No extra arguments are expected for a RAM database instance, but "
				+ cflib::CFLibXmlUtil::formatInt64( (int64_t)( argc - consumed ) )
				+ " extra arguments were specified.  Extra arguments ignored." );
		}
		else {
			std::cerr << "$SchemaName$RamLdr.evaluateRemainingArgs() WARNING No extra arguments are expected for a RAM database instance, but "
				+ cflib::CFLibXmlUtil::formatInt64( (int64_t)( argc - consumed ) )
				+ " extra arguments were specified.  Extra arguments ignored.\\n";
		}
	}
}
